import{_ as o,o as s,c as i,a2 as t}from"./chunks/framework.BWuWLRhz.js";const h=JSON.parse('{"title":"Epic 16: Docs Site & Landing Page","description":"","frontmatter":{},"headers":[],"relativePath":"epics/docs.md","filePath":"epics/docs.md"}'),d={name:"epics/docs.md"};function c(a,e,r,l,n,p){return s(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="epic-16-docs-site-landing-page" tabindex="-1">Epic 16: Docs Site &amp; Landing Page <a class="header-anchor" href="#epic-16-docs-site-landing-page" aria-label="Permalink to &quot;Epic 16: Docs Site &amp; Landing Page&quot;">​</a></h1><blockquote><p>Public VitePress site that renders <code>docs/</code> as navigable web documentation and serves as the project&#39;s landing page.</p></blockquote><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>⏳ In Progress</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Sovereign&#39;s documentation lives in <code>docs/</code> as Markdown and is currently only readable as raw files on GitHub. This epic adds a VitePress workspace app (<code>apps/docs/</code>) that builds a static site from that content without moving or duplicating any files — <code>docs/</code> remains the one source of truth.</p><p>The same site doubles as the project&#39;s landing page via a VitePress home layout page, eliminating the need for a separate marketing site at v1. A GitHub Actions workflow deploys the static output to <code>sovereignfs/sovereignfs.github.io</code> on <code>docs-v*</code> tag pushes, serving the public site at <code>https://sovereignfs.github.io/</code>.</p><p>The two tasks are sequenced: scaffold the navigable docs site first (so the full documentation is immediately browsable and the deploy pipeline is live), then layer on the landing home page (so first-time visitors are oriented before diving into docs).</p><h2 id="tasks" tabindex="-1">Tasks <a class="header-anchor" href="#tasks" aria-label="Permalink to &quot;Tasks&quot;">​</a></h2><h4 id="✅-16-1-—-apps-docs-—-vitepress-workspace-scaffold" tabindex="-1">✅ 16.1 — apps/docs — VitePress workspace scaffold <a class="header-anchor" href="#✅-16-1-—-apps-docs-—-vitepress-workspace-scaffold" aria-label="Permalink to &quot;✅ 16.1 — apps/docs — VitePress workspace scaffold&quot;">​</a></h4><p><strong>Goal:</strong> Create <code>apps/docs/</code> as a pnpm workspace package containing a VitePress 1.x config with <code>srcDir: &#39;../../docs&#39;</code>, full sidebar navigation matching the existing docs structure, and local full-text search. Running <code>pnpm --filter @sovereignfs/docs dev</code> opens the site at localhost:5173. Merges with a <code>docs-v*</code> tag trigger a deploy job that publishes the built site to <code>sovereignfs/sovereignfs.github.io</code>.</p><p><strong>Deliverables:</strong></p><ul><li><code>apps/docs/package.json</code> — <code>name: &quot;@sovereignfs/docs&quot;</code>, <code>private: true</code>; devDeps: <code>vitepress@^1</code>; scripts: <code>dev</code>, <code>build</code>, <code>preview</code></li><li><code>apps/docs/tsconfig.json</code> — extends <code>@sovereignfs/tsconfig/base.json</code></li><li><code>apps/docs/.vitepress/config.ts</code> — <code>defineConfig</code> with: <ul><li><code>srcDir: &#39;../../docs&#39;</code>, <code>outDir: &#39;.vitepress/dist&#39;</code></li><li><code>title: &#39;Sovereign&#39;</code>, <code>description</code></li><li><code>themeConfig.nav</code> — Guide, Plugin Dev, Design System, RFCs, GitHub link</li><li><code>themeConfig.sidebar</code> — sections: Getting Started (self-hosting, architecture, security, upgrade, troubleshooting), Plugin Development (plugin-development, sdk-stability, plugin-database, design-system), Core Plugins (console, launcher, account), Contributing (development-workflow, architecture-rules, testing-e2e, roadmap), RFCs</li><li><code>themeConfig.search: { provider: &#39;local&#39; }</code></li><li><code>themeConfig.socialLinks</code> — GitHub repo link</li></ul></li><li><code>apps/docs/.vitepress/theme/index.ts</code> — re-exports default VitePress theme (placeholder for future custom theme)</li><li><code>turbo.json</code> update — add <code>@sovereignfs/docs#build</code> with <code>outputs: [&#39;apps/docs/.vitepress/dist/**&#39;]</code>; no inter-package dependency needed</li><li><code>.github/workflows/docs.yml</code> — two jobs: <ul><li><code>build</code>: triggered on PRs with path filter <code>docs/**</code> or <code>apps/docs/**</code>; runs <code>pnpm --filter @sovereignfs/docs build</code> (smoke-test, no deploy)</li><li><code>deploy</code>: triggered on <code>docs-v*</code> tag push (or <code>workflow_dispatch</code>); builds then pushes <code>apps/docs/.vitepress/dist/</code> to <code>sovereignfs/sovereignfs.github.io</code> via <code>peaceiris/actions-gh-pages@v4</code> using PAT secret <code>DOCS_DEPLOY_TOKEN</code></li></ul></li></ul><p><strong>Prerequisites (manual):</strong> generate a GitHub PAT with <code>repo</code> scope for <code>sovereignfs/sovereignfs.github.io</code>; add it as secret <code>DOCS_DEPLOY_TOKEN</code> in this repo&#39;s Actions settings.</p><p><strong>SRS reference:</strong> §1.1 (open-source, self-hostable positioning), §3.14 (developer experience)</p><p><strong>Review checklist:</strong></p><ul><li><code>pnpm --filter @sovereignfs/docs dev</code> starts without error at localhost:5173</li><li>All top-level <code>docs/*.md</code> files reachable via sidebar links</li><li>Local search returns results for &quot;plugin&quot;, &quot;auth&quot;, &quot;SDK&quot;</li><li><code>pnpm --filter @sovereignfs/docs build</code> exits 0 and emits <code>apps/docs/.vitepress/dist/</code></li><li>CI <code>build</code> job passes on a test PR touching <code>docs/architecture.md</code></li><li>On <code>docs-v*</code> tag push, <code>deploy</code> job runs and <code>https://sovereignfs.github.io/</code> updates</li><li><code>pnpm lint</code> and <code>pnpm format:check</code> pass (apps/docs/ is in lint scope)</li><li>No content copied or symlinked into <code>apps/docs/</code> — all sidebar links resolve via srcDir</li></ul><h4 id="✅-16-2-—-docs-index-md-—-landing-home-page" tabindex="-1">✅ 16.2 — docs/index.md — Landing home page <a class="header-anchor" href="#✅-16-2-—-docs-index-md-—-landing-home-page" aria-label="Permalink to &quot;✅ 16.2 — docs/index.md — Landing home page&quot;">​</a></h4><p><strong>Goal:</strong> Add <code>docs/index.md</code> using VitePress built-in <code>layout: home</code> frontmatter so the site root shows a proper landing page — hero headline, feature tiles, and CTA buttons linking to the self-hosting guide and the GitHub repo.</p><p><strong>Deliverables:</strong></p><ul><li><code>docs/index.md</code> — frontmatter with: <ul><li><code>layout: home</code></li><li><code>hero</code>: name (&quot;Sovereign&quot;), tagline, actions (<code>{ text: &#39;Get Started&#39;, link: &#39;/self-hosting&#39; }</code> + <code>{ text: &#39;GitHub&#39;, link: &#39;...&#39;, theme: &#39;alt&#39; }</code>)</li><li><code>features</code>: 6–8 tiles covering self-hostable, privacy-first, plugin-first, single-tenant/multi-user, SDK contract, design system, Docker-ready, open source</li></ul></li><li><code>apps/docs/.vitepress/config.ts</code> minor update — verify <code>themeConfig.logo</code> path if a logo asset exists in the repo</li></ul><p><strong>SRS reference:</strong> §1.1, §1.2 (product positioning)</p><p><strong>Review checklist:</strong></p><ul><li>Visiting <code>http://localhost:5173/</code> shows hero + feature tiles (not raw Markdown)</li><li>&quot;Get Started&quot; CTA navigates to the self-hosting guide page</li><li>&quot;GitHub&quot; link has the correct <code>href</code></li><li>Dark mode toggle renders the home page without contrast issues</li><li><code>pnpm --filter @sovereignfs/docs build</code> exits 0 after adding <code>docs/index.md</code></li><li>No existing <code>docs/*.md</code> file is modified — <code>docs/index.md</code> is purely additive</li></ul><h2 id="related-rfcs" tabindex="-1">Related RFCs <a class="header-anchor" href="#related-rfcs" aria-label="Permalink to &quot;Related RFCs&quot;">​</a></h2><ul><li><a href="./../rfcs/0037-vitepress-docs-site.html">RFC 0037 — VitePress public docs site and project landing page</a></li></ul><h2 id="related-docs" tabindex="-1">Related Docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related Docs&quot;">​</a></h2><ul><li><a href="./../self-hosting.html">self-hosting.md — Primary &quot;Get Started&quot; destination</a></li><li><a href="./../development-workflow.html">development-workflow.md — Task workflow</a></li></ul><h2 id="cross-references" tabindex="-1">Cross-references <a class="header-anchor" href="#cross-references" aria-label="Permalink to &quot;Cross-references&quot;">​</a></h2><ul><li>Epic 0 (Infrastructure) — CI pipeline; <code>docs.yml</code> follows the same pattern as the existing <code>storybook-build</code> CI job added in task 1.0.08</li><li>Epic 9 (Theming) — if a custom VitePress theme is added post-v1, it will consume <code>--sv-*</code> design tokens from <code>packages/ui</code></li></ul>',30)])])}const g=o(d,[["render",c]]);export{h as __pageData,g as default};
